#!/usr/bin/env python3
import os
BASE=os.path.dirname(os.path.abspath(__file__))
def w(p,c):
    fp=os.path.join(BASE,p); os.makedirs(os.path.dirname(fp),exist_ok=True); open(fp,'w',encoding='utf-8').write(c); print('✓',p)
w('client/src/core/Physics.js', "// Physics.js v3 — CapRush\n// CORRECAO: agua aumenta atrito (freia), grama diminui (desliza/acelera)\n// NOVO: setVel(), bounce() para ricochete correto\nvar Physics = (function(){\n  var BASE_DRAG = 1.8;\n  var MAX_PX    = 165;\n  var MAX_SPD   = 620;\n  var REST      = 0.72;\n  var MIN_SPD   = 6;\n\n  // FIX v3: valores corrigidos (estavam invertidos!)\n  // agua:  MAIS atrito  = dragCoeff MAIOR = tampinha FREIA na agua\n  // grama: MENOS atrito = dragCoeff MENOR = tampinha DESLIZA e ACELERA na grama\n  var DRAG_MULT = {\n    asfalto: 1.0,\n    agua:    1.95,  // +95% de arrasto — freia significativamente\n    grama:   0.42,  // -58% de arrasto — desliza e ganha velocidade\n  };\n\n  var s = {\n    pos: new Vector2D(0,0),\n    vel: new Vector2D(0,0),\n    moving: false,\n    surf: 'asfalto'\n  };\n\n  function reset(x, y, surf){\n    s.pos    = new Vector2D(x, y);\n    s.vel    = new Vector2D(0, 0);\n    s.moving = false;\n    s.surf   = surf || 'asfalto';\n  }\n\n  function setSurface(surf){ s.surf = surf || 'asfalto'; }\n\n  // NOVO v3: define velocidade diretamente (para ricochete)\n  function setVel(vx, vy){\n    s.vel    = new Vector2D(vx, vy);\n    s.moving = s.vel.magnitude() > MIN_SPD;\n  }\n\n  // NOVO v3: reflexao vetorial correta — n deve ser vetor unitario\n  // Uso: bounce(nx, ny, restitution)\n  // Aplica: v = v - 2*(v.n)*n  depois multiplica por restituicao\n  function bounce(nx, ny, restitution){\n    var r   = (restitution !== undefined) ? restitution : REST;\n    var dot = s.vel.x * nx + s.vel.y * ny;\n    if(dot >= 0) return;  // ja se afastando, nao ricocheta\n    s.vel.x = (s.vel.x - 2 * dot * nx) * r;\n    s.vel.y = (s.vel.y - 2 * dot * ny) * r;\n    s.moving = s.vel.magnitude() > MIN_SPD;\n  }\n\n  function flick(from, to, charMult){\n    var drag = from.sub(to);\n    var len  = Math.min(drag.magnitude(), MAX_PX);\n    var t    = len / MAX_PX;\n    s.vel    = drag.normalize().scale(t * MAX_SPD * (charMult || 1));\n    s.moving = true;\n    return { forcePct: Math.round(t*100),\n             angle: Math.atan2(drag.y, drag.x) * 180 / Math.PI };\n  }\n\n  function step(dt, bounds){\n    if(!s.moving) return snap();\n\n    var dragCoeff = BASE_DRAG * (DRAG_MULT[s.surf] || 1.0);\n    var spd       = s.vel.magnitude();\n    var newSpd    = Math.max(0, spd - dragCoeff * spd * dt);\n\n    if(newSpd < MIN_SPD){\n      s.vel    = new Vector2D(0, 0);\n      s.moving = false;\n      return snap();\n    }\n\n    s.vel = s.vel.normalize().scale(newSpd);\n    s.pos = s.pos.add(s.vel.scale(dt));\n\n    // bordas do canvas\n    var r = 14;\n    if(s.pos.x - r < bounds.x)         { s.pos.x = bounds.x + r;           s.vel.x =  Math.abs(s.vel.x) * REST; }\n    if(s.pos.x + r > bounds.x+bounds.w){ s.pos.x = bounds.x+bounds.w - r;  s.vel.x = -Math.abs(s.vel.x) * REST; }\n    if(s.pos.y - r < bounds.y)         { s.pos.y = bounds.y + r;           s.vel.y =  Math.abs(s.vel.y) * REST; }\n    if(s.pos.y + r > bounds.y+bounds.h){ s.pos.y = bounds.y+bounds.h - r;  s.vel.y = -Math.abs(s.vel.y) * REST; }\n\n    return snap();\n  }\n\n  function snap(){\n    return {\n      pos:    s.pos.clone(),\n      vel:    s.vel.clone(),\n      speed:  s.vel.magnitude(),\n      moving: s.moving,\n      surf:   s.surf\n    };\n  }\n\n  return {\n    reset:reset, flick:flick, step:step,\n    setSurface:setSurface, setVel:setVel, bounce:bounce,\n    MAX_PX:MAX_PX, MAX_SPD:MAX_SPD, REST:REST,\n    get pos(){ return s.pos.clone(); }\n  };\n})();\n")
w('client/src/scenes/TrackV3.js', "// TrackV3.js v4 — CapRush Overdrive!\n// FIXES v4:\n//  - Paddock REMOVIDO da esquerda -> DIREITO INFERIOR EXTERNO (nao bloqueia mais largada)\n//  - Start/finish EXPANDIDO como pista real com reta dos boxes\n//  - CP1 movido para CIMA (fora da agua)\n//  - 2a poca movida para DENTRO da pista (reta direita)\n//  - Grama on-track: formato ORGANICO (blob bezier), nao retangular\n//  - Grama central: mais arvores + hastes animadas\n//  - Lago: ripples expandindo + sparkles + reflexo\n//  - Stands: finos e decorativos nas bordas\nvar TrackV3 = (function(){\n  'use strict';\n  var META = { id:'04', nome:'Terra & Cascalho v4', superficie:'asfalto', voltas:2 };\n  var CW=800, CH=500, TW=50;\n  var pts=[], puddleZones=[], grassOnTrack=[], innerBounds=[], cps=[], obstacles=[];\n  var startRect=null, startExtended=null;\n  var standZones=[], paddockZone=null;\n  var crowd=[], grassBlades=[], lakeSparkles=[];\n\n  function init(cw, ch){\n    CW=cw; CH=ch;\n    TW = Math.min(cw, ch) * 0.095;\n    var m = TW * 0.85;\n\n    pts = [\n      {x:m,         y:CH*0.46},\n      {x:m,         y:m},\n      {x:CW*0.36,   y:m},\n      {x:CW*0.44,   y:CH*0.24},\n      {x:CW*0.50,   y:CH*0.33},\n      {x:CW*0.56,   y:CH*0.24},\n      {x:CW*0.64,   y:m},\n      {x:CW-m,      y:m},\n      {x:CW-m,      y:CH*0.60},\n      {x:CW*0.75,   y:CH*0.72},\n      {x:CW*0.62,   y:CH-m},\n      {x:CW*0.50,   y:CH-m},\n      {x:CW*0.38,   y:CH-m},\n      {x:CW*0.25,   y:CH*0.72},\n      {x:m,         y:CH*0.60},\n      {x:m,         y:CH*0.46},\n    ];\n\n    // FIX v4: startRect EXPANDIDO - cobre toda a largura da pista na reta esquerda\n    // Para as tampinhas passarem livremente\n    startRect = {\n\n      x: m - TW*0.5,\n\n      y: CH*0.46,\n\n      w: TW,\n\n      h: 14,\n\n    };\n    // Area visual estendida (decorativa - barra de pit lane)\n    startExtended = {\n      x: 0, y: CH*0.36,\n      w: m + TW*0.55 + 8, h: CH*0.20\n    };\n\n    // FIX v4: CP1 movido para CIMA - fora da agua, no topo do chicane\n    // CP2 na reta direita, CP3 na base\n    cps = [\n      { x: CW*0.50, y: CH*0.18, r: TW*0.62, lbl:'CP 1', ok:false },\n      { x: CW-m,    y: CH*0.30, r: TW*0.62, lbl:'CP 2', ok:false },\n      { x: CW*0.50, y: CH-m,    r: TW*0.62, lbl:'CP 3', ok:false },\n    ];\n\n    obstacles = [\n      { x: CW*0.38, y: m + TW*0.3,        r: 8 },\n      { x: CW*0.62, y: m + TW*0.3,        r: 8 },\n      { x: CW-m,    y: CH*0.22,            r: 7 },\n      { x: CW*0.70, y: CH*0.72 + TW*0.1,  r: 8 },\n      { x: CW*0.50, y: CH-m - TW*0.18,    r: 7 },\n    ];\n\n    // FIX v4: Poca 1 no chicane central, Poca 2 na RETA DIREITA (dentro da pista)\n    puddleZones = [\n      { x: CW*0.50, y: CH*0.52, r: TW*0.60 },  // poca 1: curva do chicane\n      { x: CW*0.78, y: CH*0.50, r: TW*0.55 },  // poca 2: RETA DIREITA - CORRIGIDA\n    ];\n\n    // FIX v4: Grama on-track em formato ORGANICO (blob) - colisao via elipse\n    grassOnTrack = [\n      { type:'blob', cx:CW*0.30, cy:CH*0.80, rx:TW*0.50, ry:TW*0.34, rot:0.28 },\n      { type:'blob', cx:CW*0.66, cy:CH*0.80, rx:TW*0.46, ry:TW*0.30, rot:-0.22 },\n    ];\n\n    var innerX = m + TW + 5;\n    var innerY = m + TW + 5;\n    var innerW = CW - 2*(m + TW) - 10;\n    var innerH = CH - 2*(m + TW) - 10;\n    innerBounds = [\n      { type:'lake',  x:CW*0.38, y:CH*0.30, w:CW*0.24, h:CH*0.22, shape:'ellipse' },\n      { type:'grass', x:innerX,      y:innerY, w:CW*0.36-innerX,        h:innerH },\n      { type:'grass', x:CW*0.62,     y:innerY, w:innerX+innerW-CW*0.62, h:innerH },\n      { type:'grass', x:CW*0.36,     y:innerY, w:CW*0.28, h:CH*0.28 },\n      { type:'grass', x:CW*0.36,     y:CH*0.54, w:CW*0.28, h:innerY+innerH-CH*0.54 },\n    ];\n\n    // Stands FINOS - apenas borda superior e inferior externas (nao bloqueiam pista)\n    standZones = [\n      // Topo (acima da reta topo da pista) - very thin\n      { x:CW*0.10, y:0, w:CW*0.55, h:Math.max(m-TW*0.6, 6),\n        nx:0, ny:1, label:'STANDS' },\n      // Borda inferior (abaixo da curva de baixo)\n      { x:CW*0.28, y:CH-Math.max(m-TW*0.5, 6), w:CW*0.44, h:Math.max(m-TW*0.5, 6),\n        nx:0, ny:-1, label:'STANDS' },\n    ];\n\n    // FIX v4: PADDOCK no CANTO INFERIOR DIREITO - completamente fora da pista\n    // A pista curva de pts[8]=(CW-m, CH*0.60) para pts[9]=(CW*0.75, CH*0.72)\n    // Paddock em x>CW*0.78, y>CH*0.72 e seguro\n    paddockZone = {\n      x: CW*0.79, y: CH*0.72,\n      w: CW*0.19, h: CH*0.26,\n      nx: -1, ny: 0,\n      label: 'PADDOCK'\n    };\n\n    _initCrowd();\n    _initGrassBlades();\n    _initLakeSparkles();\n  }\n\n  function _initCrowd(){\n    crowd = [];\n    standZones.forEach(function(sz){\n      var step = 7;\n      var cols = Math.floor(sz.w / step);\n      var rows = Math.max(1, Math.floor(sz.h * 0.7 / 9));\n      for(var r=0;r<rows;r++) for(var c=0;c<cols;c++){\n        crowd.push({\n          x: sz.x + 4 + c * step,\n          y: sz.y + sz.h * 0.1 + r * 9,\n          color:['#FF4444','#4488FF','#44AA44','#FFEE22','#FF44FF','#44FFFF'][(r*17+c*7)%6],\n          phase:(r*cols+c)*0.31, sz:sz\n        });\n      }\n    });\n  }\n\n  function _initGrassBlades(){\n    grassBlades = [];\n    // Hastes na grama interior\n    for(var i=0;i<500;i++) grassBlades.push({\n      rx:Math.random(), ry:Math.random(),\n      h:3+Math.random()*5, phase:Math.random()*Math.PI*2,\n      type:'inner'\n    });\n    // Hastes on-track grass\n    grassOnTrack.forEach(function(g,gi){\n      var n = Math.floor(Math.PI * g.rx * g.ry / 8);\n      for(var i=0;i<n;i++) grassBlades.push({\n        gIdx:gi, angle:Math.random()*Math.PI*2, dist:Math.random(),\n        h:3+Math.random()*4.5, phase:Math.random()*Math.PI*2, type:'track'\n      });\n    });\n  }\n\n  function _initLakeSparkles(){\n    lakeSparkles = [];\n    for(var i=0;i<18;i++) lakeSparkles.push({\n      angle:Math.random()*Math.PI*2,\n      dist:0.2+Math.random()*0.65,\n      phase:Math.random()*Math.PI*2,\n      size:1+Math.random()*2.5\n    });\n  }\n\n  // ── isOnTrack ──────────────────────────────────────────────\n  function isOnTrack(pos){\n    var minD = Infinity;\n    for(var i=0;i<pts.length-1;i++){\n      var ax=pts[i].x,ay=pts[i].y,bx=pts[i+1].x,by=pts[i+1].y;\n      var dx=bx-ax,dy=by-ay,len=Math.sqrt(dx*dx+dy*dy);\n      if(len<1) continue;\n      var t=((pos.x-ax)*dx+(pos.y-ay)*dy)/(len*len);\n      t=Math.max(0,Math.min(1,t));\n      var px=ax+t*dx,py=ay+t*dy;\n      var d=Math.sqrt((pos.x-px)*(pos.x-px)+(pos.y-py)*(pos.y-py));\n      if(d<minD) minD=d;\n    }\n    return minD < TW*0.62+16;\n  }\n  function detectInner(pos){\n    if(isOnTrack(pos)) return null;\n    for(var i=0;i<innerBounds.length;i++){\n      var z=innerBounds[i];\n      if(z.shape==='ellipse'){\n        var ex=(pos.x-(z.x+z.w/2))/(z.w/2),ey=(pos.y-(z.y+z.h/2))/(z.h/2);\n        if(ex*ex+ey*ey<=1) return z.type;\n      } else {\n        if(pos.x>=z.x&&pos.x<=z.x+z.w&&pos.y>=z.y&&pos.y<=z.y+z.h) return z.type;\n      }\n    }\n    return 'grass';\n  }\n  function detectPuddle(pos){\n    for(var i=0;i<puddleZones.length;i++){\n      var p=puddleZones[i],dx=pos.x-p.x,dy=pos.y-p.y;\n      if(Math.sqrt(dx*dx+dy*dy)<p.r) return true;\n    }\n    return false;\n  }\n  function detectGrassOnTrack(pos){\n    for(var i=0;i<grassOnTrack.length;i++){\n      var g=grassOnTrack[i];\n      if(g.type==='blob'){\n        var dx=(pos.x-g.cx)/g.rx, dy=(pos.y-g.cy)/g.ry;\n        var cosR=Math.cos(-g.rot),sinR=Math.sin(-g.rot);\n        var rdx=cosR*dx-sinR*dy, rdy=sinR*dx+cosR*dy;\n        if(rdx*rdx+rdy*rdy<=1) return true;\n      }\n    }\n    return false;\n  }\n  function checkStands(pos,r){\n    r=r||14;\n    for(var i=0;i<standZones.length;i++){\n      var s=standZones[i];\n      if(pos.x+r>s.x&&pos.x-r<s.x+s.w&&pos.y+r>s.y&&pos.y-r<s.y+s.h)\n        return{zone:s,nx:s.nx,ny:s.ny};\n    }\n    return null;\n  }\n  function checkPaddock(pos,r){\n    r=r||14;\n    if(!paddockZone) return null;\n    var p=paddockZone;\n    if(pos.x+r>p.x&&pos.x-r<p.x+p.w&&pos.y+r>p.y&&pos.y-r<p.y+p.h)\n      return{zone:p,nx:p.nx,ny:p.ny};\n    return null;\n  }\n  function resetCPs(){ cps.forEach(function(c){c.ok=false;}); }\n  function checkCP(pos,onCp){\n    for(var i=0;i<cps.length;i++){\n      var c=cps[i]; if(c.ok) continue;\n      var dx=pos.x-c.x,dy=pos.y-c.y;\n      if(Math.sqrt(dx*dx+dy*dy)<c.r){c.ok=true;if(onCp)onCp(c);return c;}\n    }\n    return null;\n  }\n  function lastCP(){ var l=null; cps.forEach(function(c){if(c.ok)l=c;}); return l; }\n  function checkLap(pos){\n    if(!startRect) return false;\n    var s=startRect;\n    return(pos.x>=s.x&&pos.x<=s.x+s.w&&pos.y>=s.y-5&&pos.y<=s.y+s.h+5);\n  }\n  function checkObstacles(pos,r){\n    for(var i=0;i<obstacles.length;i++){\n      var o=obstacles[i],dx=pos.x-o.x,dy=pos.y-o.y,dist=Math.sqrt(dx*dx+dy*dy);\n      if(dist<r+o.r) return{obs:o,nx:dx/dist,ny:dy/dist};\n    }\n    return null;\n  }\n  function getStartPos(){\n    if(!startRect) return{x:80,y:CH/2};\n    return{x:startRect.x+startRect.w+22, y:startRect.y+startRect.h/2};\n  }\n\n  // ── RENDER ─────────────────────────────────────────────────\n  function render(ctx, cw, ch, t){\n    if(!pts.length) init(cw,ch);\n\n    // Fundo\n    ctx.fillStyle='#1A1208'; ctx.fillRect(0,0,cw,ch);\n    ctx.fillStyle='rgba(70,50,30,.32)';\n    for(var i=0;i<240;i++) ctx.fillRect((i*137.5)%cw,(i*97.3)%ch,2,2);\n\n    // ── PADDOCK inferior direito ──\n    if(paddockZone){\n      var pz=paddockZone;\n      var pg=ctx.createLinearGradient(pz.x,pz.y,pz.x+pz.w,pz.y+pz.h);\n      pg.addColorStop(0,'#6B2800'); pg.addColorStop(1,'#C05000');\n      ctx.fillStyle=pg; ctx.fillRect(pz.x,pz.y,pz.w,pz.h);\n      // Boxes\n      var bw=pz.w*0.82, bx=pz.x+pz.w*0.09;\n      var bh=Math.min(pz.h/5,28);\n      for(var bi=0;bi<4;bi++){\n        var by=pz.y+8+bi*(bh+7);\n        if(by+bh>pz.y+pz.h-8) break;\n        ctx.fillStyle='#180A00'; ctx.fillRect(bx,by,bw,bh);\n        ctx.strokeStyle='#FF7722'; ctx.lineWidth=1.2;\n        for(var gi=0;gi<4;gi++){\n          ctx.beginPath();ctx.moveTo(bx+bw*gi/4+2,by+2);ctx.lineTo(bx+bw*gi/4+2,by+bh-2);ctx.stroke();\n        }\n        ctx.strokeStyle='#FF5500'; ctx.lineWidth=2; ctx.strokeRect(bx-1,by-1,bw+2,bh+2);\n        ctx.fillStyle='#FF8800'; ctx.font='bold '+(Math.floor(bh*0.38))+'px Rajdhani,sans-serif';\n        ctx.textAlign='center'; ctx.fillText('BOX '+(bi+1),bx+bw/2,by+bh*0.68);\n      }\n      ctx.strokeStyle='#FF5500'; ctx.lineWidth=2.5; ctx.setLineDash([6,4]);\n      ctx.strokeRect(pz.x+1,pz.y+1,pz.w-2,pz.h-2); ctx.setLineDash([]);\n      ctx.fillStyle='rgba(255,90,0,.8)'; ctx.font='bold 11px Bebas Neue,sans-serif';\n      ctx.textAlign='center'; ctx.fillText('PADDOCK',pz.x+pz.w/2,pz.y+9);\n    }\n\n    // ── Stands finos com torcida ──\n    standZones.forEach(function(sz){\n      if(sz.h < 4) return;\n      var sg = ctx.createLinearGradient(sz.x,sz.y,sz.x,sz.y+sz.h);\n      sg.addColorStop(0,'#CCAA00'); sg.addColorStop(1,'#665500');\n      ctx.fillStyle=sg; ctx.fillRect(sz.x,sz.y,sz.w,sz.h);\n      // Torcida so se houver espaco suficiente\n      if(sz.h>10){\n        crowd.forEach(function(c){\n          if(c.sz!==sz) return;\n          var wave=Math.sin(t*2.5+c.phase)*3;\n          ctx.fillStyle=c.color; ctx.fillRect(c.x-2,c.y-wave-2,4,6);\n          ctx.fillStyle='#FFD8A8'; ctx.beginPath();ctx.arc(c.x,c.y-wave-5,2.5,0,Math.PI*2);ctx.fill();\n        });\n      }\n      ctx.strokeStyle='#FFD700'; ctx.lineWidth=2; ctx.setLineDash([8,4]);\n      ctx.strokeRect(sz.x+1,sz.y+1,sz.w-2,sz.h-2); ctx.setLineDash([]);\n    });\n\n    // ── Interior grama escura ──\n    var m2=TW*0.85+TW;\n    ctx.fillStyle='#0D2B0D';\n    _roundRect(ctx,m2,m2,cw-2*m2,ch-2*m2,14); ctx.fill();\n\n    // Grama interior - listras diagonais de fundo\n    ctx.strokeStyle='rgba(0,120,0,.14)'; ctx.lineWidth=1;\n    for(var gx=0;gx<cw;gx+=8){\n      ctx.beginPath();ctx.moveTo(gx,0);ctx.lineTo(gx-20,ch);ctx.stroke();\n    }\n\n    // Hastes de grama animadas (interior)\n    var innerXb=m2, innerYb=m2, innerWb=cw-2*m2, innerHb=ch-2*m2;\n    grassBlades.forEach(function(b){\n      if(b.type!=='inner') return;\n      var bx=innerXb+b.rx*innerWb, by=innerYb+b.ry*innerHb;\n      var lean=Math.sin(t*1.8+b.phase)*3;\n      ctx.strokeStyle='rgba('+(30+Math.floor(b.h*10))+',200,40,.55)';\n      ctx.lineWidth=1;\n      ctx.beginPath();ctx.moveTo(bx,by);\n      ctx.quadraticCurveTo(bx+lean,by-b.h*.5,bx+lean*.6,by-b.h);\n      ctx.stroke();\n    });\n\n    // MAIS ARVORES (16 posicoes em vez de 8)\n    var treePos=[\n      [cw*0.18,ch*0.22],[cw*0.28,ch*0.35],[cw*0.16,ch*0.48],[cw*0.20,ch*0.62],\n      [cw*0.28,ch*0.50],[cw*0.22,ch*0.38],\n      [cw*0.72,ch*0.20],[cw*0.82,ch*0.35],[cw*0.76,ch*0.48],[cw*0.72,ch*0.62],\n      [cw*0.82,ch*0.50],[cw*0.76,ch*0.38],\n      [cw*0.38,ch*0.72],[cw*0.50,ch*0.70],[cw*0.62,ch*0.72],[cw*0.50,ch*0.78],\n    ];\n    treePos.forEach(function(tp){\n      // Sombra da arvore\n      ctx.fillStyle='rgba(0,0,0,.18)';\n      ctx.beginPath();ctx.ellipse(tp[0]+5,tp[1]+14,12,5,0,0,Math.PI*2);ctx.fill();\n      // Tronco\n      ctx.fillStyle='#3D2008'; ctx.fillRect(tp[0]-3,tp[1]+8,6,14);\n      // Copa em layers (efeito 3D)\n      [[16,'#1A5C1A'],[12,'#1E7020'],[8,'#28902A'],[4,'#38B838']].forEach(function(l){\n        ctx.fillStyle=l[1];\n        ctx.beginPath();ctx.arc(tp[0],tp[1]-2,l[0],0,Math.PI*2);ctx.fill();\n      });\n      // Brilho no topo\n      ctx.fillStyle='rgba(80,220,80,.25)';\n      ctx.beginPath();ctx.ellipse(tp[0]-3,tp[1]-8,5,3,-0.5,0,Math.PI*2);ctx.fill();\n    });\n\n    // LAGO com animacao rica\n    var lx=innerBounds[0];\n    if(lx){\n      var lcx=lx.x+lx.w/2, lcy=lx.y+lx.h/2;\n      var lrx=lx.w/2, lry=lx.h/2;\n      // Base do lago\n      var lgrd=ctx.createRadialGradient(lcx-lrx*.2,lcy-lry*.2,2,lcx,lcy,lrx);\n      lgrd.addColorStop(0,'rgba(40,160,255,.9)');\n      lgrd.addColorStop(.35,'rgba(10,100,220,.75)');\n      lgrd.addColorStop(.7,'rgba(0,60,180,.6)');\n      lgrd.addColorStop(1,'rgba(0,30,120,.35)');\n      ctx.fillStyle=lgrd;\n      ctx.beginPath();ctx.ellipse(lcx,lcy,lrx,lry,0,0,Math.PI*2);ctx.fill();\n      // Ripples expandindo\n      for(var ri=0;ri<5;ri++){\n        var rphase=(t*0.7+ri*0.55)%(Math.PI*2);\n        var rscale=0.15+0.55*(rphase/(Math.PI*2));\n        var ralpha=0.35*(1-rphase/(Math.PI*2));\n        ctx.strokeStyle='rgba(120,210,255,'+ralpha+')';\n        ctx.lineWidth=1.5;\n        ctx.beginPath();ctx.ellipse(lcx,lcy,lrx*rscale,lry*rscale,Math.sin(t*.3)*.08,0,Math.PI*2);ctx.stroke();\n      }\n      // Reflexo de luz (shimmer)\n      var shimmerX=lcx-lrx*.3+Math.sin(t*1.2)*lrx*.25;\n      var shimmerY=lcy-lry*.2+Math.cos(t*.9)*lry*.15;\n      ctx.fillStyle='rgba(255,255,255,.12)';\n      ctx.beginPath();ctx.ellipse(shimmerX,shimmerY,lrx*.25,lry*.1,-0.4,0,Math.PI*2);ctx.fill();\n      // Sparkles do lago\n      lakeSparkles.forEach(function(sp){\n        var sx=lcx+Math.cos(sp.angle+t*.2)*lrx*sp.dist;\n        var sy=lcy+Math.sin(sp.angle+t*.2)*lry*sp.dist;\n        var spAlpha=0.4+0.4*Math.sin(t*3+sp.phase);\n        ctx.fillStyle='rgba(200,240,255,'+spAlpha+')';\n        ctx.beginPath();ctx.arc(sx,sy,sp.size*(0.7+0.3*Math.sin(t*2+sp.phase)),0,Math.PI*2);ctx.fill();\n      });\n    }\n\n    // ── Borda e faixa da pista ──\n    _drawPath(ctx, TW+18, '#2A1F18');\n    _drawPath(ctx, TW,    '#5C4530');\n    ctx.save(); ctx.strokeStyle='rgba(0,0,0,.12)'; ctx.lineWidth=1; ctx.setLineDash([4,8]);\n    _drawPathStroke(ctx); ctx.setLineDash([]); ctx.restore();\n    ctx.save(); ctx.strokeStyle='rgba(255,215,0,.32)'; ctx.lineWidth=2; ctx.setLineDash([12,10]);\n    _drawPathStroke(ctx); ctx.setLineDash([]); ctx.restore();\n\n    // ── Pocas organicas ──\n    puddleZones.forEach(function(p){\n      _drawOrganicPuddle(ctx,p.x,p.y,p.r,t);\n    });\n\n    // ── Grama on-track ORGANICA ──\n    grassOnTrack.forEach(function(g,gi){\n      if(g.type!=='blob') return;\n      // Desenha blob organico com bezier\n      ctx.save();ctx.translate(g.cx,g.cy);ctx.rotate(g.rot);\n      var n=8;\n      var gGrd=ctx.createRadialGradient(0,0,2,0,0,Math.max(g.rx,g.ry));\n      gGrd.addColorStop(0,'rgba(80,230,70,.55)');\n      gGrd.addColorStop(1,'rgba(30,180,30,.2)');\n      ctx.fillStyle=gGrd;\n      ctx.beginPath();\n      for(var bi2=0;bi2<n;bi2++){\n        var ang=bi2/n*Math.PI*2;\n        var wobble=1+0.18*Math.sin(t*1.2+bi2*1.4);\n        var px=g.rx*wobble*Math.cos(ang), py=g.ry*wobble*Math.sin(ang);\n        if(bi2===0) ctx.moveTo(px,py); else ctx.lineTo(px,py);\n      }\n      ctx.closePath(); ctx.fill();\n      ctx.strokeStyle='rgba(50,210,50,.75)'; ctx.lineWidth=2; ctx.stroke();\n      ctx.restore();\n      // Hastes on-track\n      grassBlades.forEach(function(b){\n        if(b.type!=='track'||b.gIdx!==gi) return;\n        var ang=b.angle, dist=b.dist;\n        var bx2=g.cx+Math.cos(ang+g.rot)*g.rx*dist;\n        var by2=g.cy+Math.sin(ang+g.rot)*g.ry*dist;\n        var lean=Math.sin(t*2+b.phase)*2.8;\n        ctx.strokeStyle='rgba(40,220,40,.65)'; ctx.lineWidth=1;\n        ctx.beginPath();ctx.moveTo(bx2,by2);\n        ctx.quadraticCurveTo(bx2+lean,by2-b.h*.5,bx2+lean*.6,by2-b.h);\n        ctx.stroke();\n      });\n    });\n\n    // ── Obstaculos ──\n    obstacles.forEach(function(o){\n      ctx.fillStyle='rgba(0,0,0,.28)';\n      ctx.beginPath();ctx.ellipse(o.x+3,o.y+3,o.r+2,o.r+1,0,0,Math.PI*2);ctx.fill();\n      ctx.fillStyle='#5C3A1A';ctx.beginPath();ctx.arc(o.x,o.y,o.r,0,Math.PI*2);ctx.fill();\n      ctx.fillStyle='#7A5030';ctx.beginPath();ctx.arc(o.x-1,o.y-2,o.r*.5,0,Math.PI*2);ctx.fill();\n      ctx.strokeStyle='#3A2010';ctx.lineWidth=1.5;ctx.beginPath();ctx.arc(o.x,o.y,o.r,0,Math.PI*2);ctx.stroke();\n    });\n\n    // ── START/FINISH expandido (pit straight) ──\n    if(startRect){\n      var sl=startRect;\n      var sq=8;\n      var nc=Math.ceil(sl.w/sq), nr=Math.ceil(sl.h/sq);\n      for(var row=0;row<nr;row++) for(var col=0;col<nc;col++){\n        ctx.fillStyle=(row+col)%2===0?'#FFFFFF':'#111111';\n        ctx.fillRect(sl.x+col*sq, sl.y+row*sq, sq, sq);\n      }\n      // Borda dourada\n      ctx.strokeStyle='#FFD700'; ctx.lineWidth=3;\n      ctx.strokeRect(sl.x,sl.y,sl.w,sl.h);\n      // Label\n      ctx.fillStyle='#FFD700'; ctx.font='bold 8px Rajdhani,sans-serif';\n      ctx.textAlign='center';\n      ctx.fillText('START / FINISH', sl.x+sl.w/2, sl.y-4);\n      // Pit lane marking\n      ctx.fillStyle='rgba(255,120,0,.5)';\n      ctx.fillRect(sl.x, sl.y+sl.h+2, sl.w, 4);\n      ctx.fillStyle='rgba(255,180,0,.4)';\n      ctx.font='bold 7px Rajdhani,sans-serif'; ctx.textAlign='center';\n      ctx.fillText('PIT LANE', sl.x+sl.w/2, sl.y+sl.h+12);\n    }\n\n    // ── Checkpoints ──\n    cps.forEach(function(c){\n      ctx.save(); ctx.globalAlpha=c.ok?.25:.88;\n      ctx.fillStyle=c.ok?'rgba(40,40,40,.3)':'rgba(255,255,255,.14)';\n      ctx.beginPath();ctx.arc(c.x,c.y,c.r*.6,0,Math.PI*2);ctx.fill();\n      ctx.strokeStyle=c.ok?'#333':'#FFF'; ctx.lineWidth=3; ctx.setLineDash([5,3]);\n      ctx.beginPath();ctx.arc(c.x,c.y,c.r*.6,0,Math.PI*2);ctx.stroke();\n      ctx.setLineDash([]);\n      ctx.fillStyle=c.ok?'#333':'#FFF'; ctx.font='bold 10px Rajdhani,sans-serif';\n      ctx.textAlign='center'; ctx.fillText(c.lbl,c.x,c.y-c.r*.6-5);\n      ctx.restore();\n    });\n  }\n\n  // Poca organica\n  function _drawOrganicPuddle(ctx,cx,cy,r,t){\n    var n=9, pts2=[];\n    for(var i=0;i<n;i++){\n      var a=i/n*Math.PI*2;\n      var w2=1+0.2*Math.sin(t*1.3+i*1.2+0.5);\n      pts2.push({x:cx+Math.cos(a)*r*w2, y:cy+Math.sin(a)*r*0.65*w2});\n    }\n    var wgrd=ctx.createRadialGradient(cx,cy,2,cx,cy,r);\n    wgrd.addColorStop(0,'rgba(40,170,255,.58)');\n    wgrd.addColorStop(.55,'rgba(0,110,220,.38)');\n    wgrd.addColorStop(1,'rgba(0,60,170,.15)');\n    ctx.fillStyle=wgrd;\n    ctx.beginPath();\n    ctx.moveTo((pts2[0].x+pts2[n-1].x)/2,(pts2[0].y+pts2[n-1].y)/2);\n    for(var i2=0;i2<n;i2++){\n      var next=pts2[(i2+1)%n];\n      ctx.quadraticCurveTo(pts2[i2].x,pts2[i2].y,(pts2[i2].x+next.x)/2,(pts2[i2].y+next.y)/2);\n    }\n    ctx.closePath(); ctx.fill();\n    ctx.strokeStyle='rgba(100,215,255,.88)'; ctx.lineWidth=2.5; ctx.setLineDash([6,3]);\n    ctx.stroke(); ctx.setLineDash([]);\n    // Onda interna\n    ctx.strokeStyle='rgba(160,235,255,'+(0.3+Math.sin(t*2)*.12)+')';\n    ctx.lineWidth=1.2;\n    ctx.beginPath();ctx.ellipse(cx+2,cy-2,r*.44,r*.27,Math.sin(t*.7)*.2,0,Math.PI*2);ctx.stroke();\n    // Reflexo\n    ctx.fillStyle='rgba(255,255,255,.16)';\n    ctx.beginPath();ctx.ellipse(cx-r*.22,cy-r*.18,r*.2,r*.08,-0.5,0,Math.PI*2);ctx.fill();\n  }\n\n  function _drawPath(ctx,width,color){\n    if(!pts.length) return;\n    ctx.save();ctx.strokeStyle=color;ctx.lineWidth=width;\n    ctx.lineCap='round';ctx.lineJoin='round';\n    ctx.beginPath();ctx.moveTo(pts[0].x,pts[0].y);\n    pts.forEach(function(p,i){if(i>0)ctx.lineTo(p.x,p.y);});\n    ctx.closePath();ctx.stroke();ctx.restore();\n  }\n  function _drawPathStroke(ctx){\n    if(!pts.length) return;\n    ctx.beginPath();ctx.moveTo(pts[0].x,pts[0].y);\n    pts.forEach(function(p,i){if(i>0)ctx.lineTo(p.x,p.y);});\n    ctx.closePath();ctx.stroke();\n  }\n  function _roundRect(ctx,x,y,w,h,r){\n    ctx.beginPath();\n    ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.quadraticCurveTo(x+w,y,x+w,y+r);\n    ctx.lineTo(x+w,y+h-r);ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);\n    ctx.lineTo(x+r,y+h);ctx.quadraticCurveTo(x,y+h,x,y+h-r);\n    ctx.lineTo(x,y+r);ctx.quadraticCurveTo(x,y,x+r,y);\n    ctx.closePath();\n  }\n\n  return {\n    META:META, init:init, render:render,\n    isOnTrack:isOnTrack, detectInner:detectInner,\n    detectPuddle:detectPuddle, detectGrassOnTrack:detectGrassOnTrack,\n    checkCP:checkCP, checkLap:checkLap, resetCPs:resetCPs,\n    checkObstacles:checkObstacles, lastCP:lastCP, getStartPos:getStartPos,\n    checkStands:checkStands, checkPaddock:checkPaddock,\n    get checkpoints(){ return cps; },\n    get TW(){ return TW; },\n  };\n})();\n")
w('client/src/GameLoop.js', '// GameLoop.js v3 — CapRush Solo\n// CORRECAO: ricochete em obstaculos usa reflexao vetorial correta (Physics.bounce)\n// NOVO: colisao com stands (ricochet REST=0.72) e paddock (ricochet REST=0.60)\n(function(){\n  \'use strict\';\n  var canvas  = document.getElementById(\'gameCanvas\');\n  var ctx     = canvas.getContext(\'2d\');\n  var overlay = document.getElementById(\'overlay\');\n  var elLap   = document.getElementById(\'hud-lap\');\n  var elCp    = document.getElementById(\'hud-cp\');\n  var elTime  = document.getElementById(\'hud-time\');\n  var elBest  = document.getElementById(\'hud-best\');\n  var elFBar  = document.getElementById(\'force-bar-fill\');\n  var elFVal  = document.getElementById(\'force-value\');\n  var logBox  = document.getElementById(\'log-box\');\n\n  var LAPS=TrackV3.META.voltas, NCPS=3, CAP_R=16;\n  var gs={phase:\'WAIT\',lap:1,cp:0,t0:0,elapsed:0,best:null,ds:null,dc:null,respawn:null};\n  var animT=0, lt=0;\n  var sndTimer={water:0,grass:0};\n\n  SoundEngine.init();\n\n  function resize(){\n    var wrap=canvas.parentElement;\n    canvas.width  = Math.max(wrap.offsetWidth - 155, 320);\n    canvas.height = Math.max(wrap.offsetHeight, 280);\n    TrackV3.init(canvas.width, canvas.height);\n    var sp=TrackV3.getStartPos();\n    Physics.reset(sp.x, sp.y, \'asfalto\');\n    Yuki.resetAnim();\n    gs.respawn={x:sp.x, y:sp.y};\n  }\n  window.addEventListener(\'resize\', resize);\n  setTimeout(resize, 80);\n\n  function startGame(){\n    SoundEngine.resume();\n    overlay.style.display=\'none\';\n    gs.phase=\'AIM\';\n    if(canvas.width<50) resize();\n    var sp=TrackV3.getStartPos();\n    Physics.reset(sp.x, sp.y, \'asfalto\');\n    gs.respawn={x:sp.x, y:sp.y};\n  }\n  overlay.addEventListener(\'click\',   startGame);\n  overlay.addEventListener(\'touchend\',function(e){e.preventDefault();startGame();},{passive:false});\n\n  function cpos(e){ var r=canvas.getBoundingClientRect(); return new Vector2D(e.clientX-r.left, e.clientY-r.top); }\n  function bnd(){ return{x:0,y:0,w:canvas.width,h:canvas.height}; }\n\n  canvas.addEventListener(\'mousedown\', function(e){\n    if(gs.phase!==\'AIM\') return; SoundEngine.resume();\n    var ph=Physics.step(0,bnd());\n    if(cpos(e).distanceTo(ph.pos)<48){ gs.ds=cpos(e); gs.dc=cpos(e); }\n  });\n  canvas.addEventListener(\'mousemove\', function(e){\n    if(!gs.ds) return; gs.dc=cpos(e);\n    var pct=Math.min(gs.ds.sub(gs.dc).magnitude()/Physics.MAX_PX,1);\n    elFBar.style.height=(pct*100)+\'%\'; elFVal.textContent=Math.round(pct*100)+\'%\';\n  });\n  canvas.addEventListener(\'mouseup\', function(e){\n    if(!gs.ds||gs.phase!==\'AIM\') return;\n    var info=Physics.flick(gs.ds,cpos(e),Yuki.M.spd);\n    log(\'Lance: \'+info.forcePct+\'% / \'+info.angle.toFixed(0)+\'\\u00b0\',\'ev\');\n    gs.ds=null; gs.dc=null; gs.phase=\'MOVING\';\n    if(!gs.t0) gs.t0=performance.now();\n    elFBar.style.height=\'0%\'; elFVal.textContent=\'0%\';\n  });\n  canvas.addEventListener(\'touchstart\',function(e){\n    if(gs.phase!==\'AIM\') return; SoundEngine.resume();\n    var ph=Physics.step(0,bnd());\n    if(cpos(e.touches[0]).distanceTo(ph.pos)<48){ gs.ds=cpos(e.touches[0]); gs.dc=cpos(e.touches[0]); }\n  },{passive:true});\n  canvas.addEventListener(\'touchmove\',function(e){\n    e.preventDefault(); if(!gs.ds) return; gs.dc=cpos(e.touches[0]);\n    var pct=Math.min(gs.ds.sub(gs.dc).magnitude()/Physics.MAX_PX,1);\n    elFBar.style.height=(pct*100)+\'%\'; elFVal.textContent=Math.round(pct*100)+\'%\';\n  },{passive:false});\n  canvas.addEventListener(\'touchend\',function(e){\n    if(!gs.ds||gs.phase!==\'AIM\') return;\n    Physics.flick(gs.ds,cpos(e.changedTouches[0]),Yuki.M.spd);\n    gs.ds=null; gs.dc=null; gs.phase=\'MOVING\';\n    if(!gs.t0) gs.t0=performance.now();\n    elFBar.style.height=\'0%\'; elFVal.textContent=\'0%\';\n  },{passive:true});\n\n  function loop(now){\n    var dt=Math.min((now-lt)/1000, 0.05); lt=now; animT+=dt;\n    ctx.clearRect(0,0,canvas.width,canvas.height);\n    TrackV3.render(ctx, canvas.width, canvas.height, animT);\n\n    var ph=Physics.step(dt, bnd());\n\n    if(ph.moving){\n      // ── Obstaculos: ricochete correto via reflexao vetorial ──\n      var obs=TrackV3.checkObstacles(ph.pos, CAP_R);\n      if(obs){\n        // FIX v3: usa Physics.bounce com normal do obstaculo (REST=0.72)\n        Physics.bounce(obs.nx, obs.ny, 0.72);\n        SoundEngine.hit();\n        log(\'Bateu em obstaculo!\');\n        ph=Physics.step(0, bnd());\n      }\n\n      // ── NOVO v3: Arquibancadas — ricochete REST=0.72 ──\n      var stand=TrackV3.checkStands(ph.pos, CAP_R);\n      if(stand){\n        Physics.bounce(stand.nx, stand.ny, 0.72);\n        SoundEngine.hit();\n        log(\'Arquibancada! Ricochete!\', \'ev\');\n        ph=Physics.step(0, bnd());\n      }\n\n      // ── NOVO v3: Paddock — ricochete REST=0.60 (solo) ──\n      var pdk=TrackV3.checkPaddock(ph.pos, CAP_R);\n      if(pdk){\n        Physics.bounce(pdk.nx, pdk.ny, 0.60);\n        SoundEngine.hit();\n        log(\'Paddock! Ricochete!\', \'ev\');\n        ph=Physics.step(0, bnd());\n      }\n\n      // Superficie especial (apenas se na pista)\n      if(TrackV3.isOnTrack(ph.pos)){\n        var now2=Date.now();\n        if(TrackV3.detectPuddle(ph.pos)){\n          Physics.setSurface(\'agua\');\n          if(now2-sndTimer.water>700){ SoundEngine.splash(); sndTimer.water=now2; }\n        } else if(TrackV3.detectGrassOnTrack(ph.pos)){\n          Physics.setSurface(\'grama\');\n          if(now2-sndTimer.grass>900){ SoundEngine.grass(); sndTimer.grass=now2; }\n        } else {\n          Physics.setSurface(\'asfalto\');\n        }\n      } else {\n        var inner=TrackV3.detectInner(ph.pos);\n        if(inner){\n          var rp=gs.respawn||TrackV3.getStartPos();\n          Physics.reset(rp.x, rp.y, \'asfalto\');\n          log(\'Zona \'+inner+\' \\u2014 voltando ao CP\');\n        }\n      }\n    }\n\n    Yuki.render(ctx, ph, dt);\n    if(gs.ds&&gs.dc) drawAim(ph.pos, gs.dc);\n\n    if(gs.phase===\'MOVING\'){\n      gs.elapsed=(performance.now()-gs.t0)/1000; updHUD();\n      if(!ph.moving){ gs.phase=\'AIM\'; log(\'Parou \\u2014 mire novamente\'); }\n      TrackV3.checkCP(ph.pos, function(c){\n        SoundEngine.checkpoint();\n        gs.cp++; elCp.textContent=gs.cp+\'/\'+NCPS;\n        gs.respawn={x:c.x, y:c.y};\n        log(c.lbl+\' ativado!\',\'ev\');\n      });\n      if(gs.cp>=NCPS&&TrackV3.checkLap(ph.pos)) onLap();\n    }\n    requestAnimationFrame(loop);\n  }\n\n  function onLap(){\n    gs.cp=0; TrackV3.resetCPs();\n    if(gs.lap>=LAPS){ gs.phase=\'FINISH\'; onFinish(); }\n    else{ gs.lap++; log(\'Volta \'+gs.lap+\' iniciada!\',\'ev\'); elLap.textContent=gs.lap+\'/\'+LAPS; }\n  }\n  function onFinish(){\n    var t=gs.elapsed;\n    if(!gs.best||t<gs.best) gs.best=t;\n    elBest.textContent=fmt(gs.best);\n    log(\'CORRIDA COMPLETA! \'+fmt(t),\'ev\');\n    SoundEngine.victory();\n    postScore(\'Yuki\',t);\n    setTimeout(function(){\n      overlay.innerHTML=\'<h2>CORRIDA COMPLETA!</h2>\'\n        +\'<p style="color:#FFD700;font-size:2rem;font-family:Bebas Neue,sans-serif">\'+fmt(t)+\'</p>\'\n        +\'<p style="color:#aaa;margin-top:.5rem">Clique para jogar novamente</p>\';\n      overlay.style.display=\'flex\';\n      overlay.onclick=function(){overlay.onclick=null;restart();};\n    },1600);\n  }\n  function restart(){\n    overlay.style.display=\'none\';\n    TrackV3.resetCPs();\n    var sp=TrackV3.getStartPos();\n    Physics.reset(sp.x,sp.y,\'asfalto\');\n    Yuki.resetAnim();\n    gs={phase:\'AIM\',lap:1,cp:0,t0:performance.now(),elapsed:0,best:gs.best,ds:null,dc:null,respawn:{x:sp.x,y:sp.y}};\n    updHUD(); logBox.innerHTML=\'\';\n    overlay.addEventListener(\'click\',startGame);\n  }\n  function updHUD(){\n    elTime.textContent=fmt(gs.elapsed);\n    elLap.textContent=gs.lap+\'/\'+LAPS;\n    elCp.textContent=gs.cp+\'/\'+NCPS;\n  }\n  function fmt(s){\n    var m=Math.floor(s/60),ss=(s%60).toFixed(1);\n    return(m<10?\'0\':\'\')+m+\':\'+(parseFloat(ss)<10?\'0\':\'\')+ss;\n  }\n  function log(msg,cls){\n    var p=document.createElement(\'p\'); if(cls)p.className=cls;\n    p.textContent=msg; logBox.insertBefore(p,logBox.firstChild);\n    while(logBox.children.length>30) logBox.removeChild(logBox.lastChild);\n  }\n  function drawAim(cap, drag){\n    var dir=cap.sub(drag).normalize();\n    var dist=Math.min(cap.distanceTo(drag),Physics.MAX_PX);\n    var end=cap.add(dir.scale(dist*1.8)), pct=dist/Physics.MAX_PX;\n    ctx.save();\n    var g=ctx.createLinearGradient(cap.x,cap.y,end.x,end.y);\n    g.addColorStop(0,\'rgba(0,229,255,\'+(0.85+pct*.15)+\')\');\n    g.addColorStop(1,\'rgba(0,229,255,0)\');\n    ctx.strokeStyle=g; ctx.lineWidth=2+pct*2.5; ctx.setLineDash([7,5]);\n    ctx.beginPath();ctx.moveTo(cap.x,cap.y);ctx.lineTo(end.x,end.y);ctx.stroke();\n    ctx.setLineDash([]);\n    ctx.beginPath();ctx.arc(cap.x,cap.y,20+pct*12,0,Math.PI*2);\n    ctx.strokeStyle=\'rgba(255,215,0,\'+(0.25+pct*.5)+\')\';\n    ctx.lineWidth=1.5; ctx.stroke();\n    ctx.restore();\n  }\n  function postScore(p,t){\n    fetch(\'http://localhost:5000/api/scores\',{\n      method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n      body:JSON.stringify({piloto:p,pista:TrackV3.META.nome,tempo:t})\n    }).then(function(){log(\'Score salvo.\',\'ev\');}).catch(function(){log(\'Servidor offline.\');});\n  }\n  requestAnimationFrame(function(t){lt=t;requestAnimationFrame(loop);});\n})();\n')
w('client/src/core/SoundEngine.js', "// SoundEngine.js  v4b  --  CapRush Overdrive!\n// BGM procedural com session-ID (sem overlap ao toggle rapido)\nvar SoundEngine = (function(){\n  var ctx = null;\n  var _bgmOn = true, _sfxOn = true;\n  var _session = 0;      // incrementado a cada startBGM/stopBGM\n  var _masterGain = null;\n  var _bgmGain = null;\n\n  function init(){\n    if(ctx) return;\n    try{\n      ctx = new (window.AudioContext||window.webkitAudioContext)();\n      _masterGain = ctx.createGain();\n      _masterGain.gain.value = 1;\n      _masterGain.connect(ctx.destination);\n      _bgmGain = ctx.createGain();\n      _bgmGain.gain.value = 0.22;\n      _bgmGain.connect(_masterGain);\n    }catch(e){}\n  }\n  function resume(){\n    if(ctx && ctx.state==='suspended') ctx.resume();\n  }\n  function beep(freq,dur,vol,type){\n    if(!ctx||!_sfxOn) return;\n    var o=ctx.createOscillator(), g=ctx.createGain();\n    o.type = type||'square';\n    o.frequency.value = freq||880;\n    g.gain.setValueAtTime(vol||0.3, ctx.currentTime);\n    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime+(dur||0.12));\n    o.connect(g); g.connect(_masterGain||ctx.destination);\n    o.start(); o.stop(ctx.currentTime+(dur||0.12));\n  }\n  function checkpoint(){\n    if(!ctx||!_sfxOn) return;\n    beep(660,.08,.35,'square');\n    setTimeout(function(){ beep(880,.1,.35,'square'); }, 90);\n  }\n  function hit(){\n    if(!ctx||!_sfxOn) return;\n    var buf=ctx.createBuffer(1,ctx.sampleRate*.12,ctx.sampleRate);\n    var d=buf.getChannelData(0);\n    for(var i=0;i<d.length;i++) d[i]=(Math.random()*2-1)*Math.pow(1-i/d.length,2)*.8;\n    var s=ctx.createBufferSource(), g=ctx.createGain();\n    g.gain.value=0.5;\n    s.buffer=buf; s.connect(g); g.connect(_masterGain||ctx.destination); s.start();\n  }\n  function splash(){\n    if(!ctx||!_sfxOn) return;\n    var buf=ctx.createBuffer(1,ctx.sampleRate*.18,ctx.sampleRate);\n    var d=buf.getChannelData(0);\n    for(var i=0;i<d.length;i++) d[i]=(Math.random()*2-1)*.25*Math.pow(1-i/d.length,1.5);\n    var s=ctx.createBufferSource(), f=ctx.createBiquadFilter(), g=ctx.createGain();\n    f.type='bandpass'; f.frequency.value=1800; g.gain.value=.7;\n    s.buffer=buf; s.connect(f); f.connect(g); g.connect(_masterGain||ctx.destination); s.start();\n  }\n  function grass(){\n    if(!ctx||!_sfxOn) return;\n    var buf=ctx.createBuffer(1,ctx.sampleRate*.15,ctx.sampleRate);\n    var d=buf.getChannelData(0);\n    for(var i=0;i<d.length;i++) d[i]=(Math.random()*2-1)*.12*Math.pow(1-i/d.length,1.2);\n    var s=ctx.createBufferSource(), f=ctx.createBiquadFilter(), g=ctx.createGain();\n    f.type='lowpass'; f.frequency.value=350; g.gain.value=.6;\n    s.buffer=buf; s.connect(f); f.connect(g); g.connect(_masterGain||ctx.destination); s.start();\n  }\n  function victory(){\n    if(!ctx) return;\n    [523,659,784,1047].forEach(function(n,i){\n      setTimeout(function(){ beep(n,.18,.32,'triangle'); }, i*115);\n    });\n    setTimeout(function(){ beep(1047,.4,.38,'triangle'); }, 480);\n  }\n\n  // ── BGM PROCEDURAL 148 BPM Am ──────────────────────────────────────────\n  // Session ID garante que loops antigos param ao fazer toggle rapido\n  var AM_BASS  = [110, 98,  98,  110, 131, 131, 110, 98 ]; // A2 G2 G2 A2 C3 C3 A2 G2\n  var AM_CHORD = [220, 196, 247, 220, 262, 247, 220, 196]; // A3 G3 B3 A3 C4 B3 A3 G3\n  var AM_LEAD  = [440, 392, 330, 440, 523, 494, 440, 392]; // A4 G4 E4 A4 C5 B4 A4 G4\n  var BEAT_MS  = (60/148/2)*1000; // 8a note\n  var BEAT_IDX = 0;\n\n  function _scheduleBeat(session){\n    if(session !== _session || !_bgmOn) return;\n    if(!ctx){ setTimeout(function(){ _scheduleBeat(session); }, BEAT_MS); return; }\n    var now = ctx.currentTime;\n    var dur = (BEAT_MS/1000) * 0.85;\n    var bi  = BEAT_IDX % 8;\n\n    // Bass sinc\n    var ob=ctx.createOscillator(), gb=ctx.createGain();\n    ob.type='sawtooth'; ob.frequency.value=AM_BASS[bi];\n    gb.gain.setValueAtTime(.28, now);\n    gb.gain.exponentialRampToValueAtTime(.001, now+dur);\n    ob.connect(gb); gb.connect(_bgmGain); ob.start(now); ob.stop(now+dur);\n\n    // Chord pad (triangle)\n    if(bi%2===0){\n      var oc=ctx.createOscillator(), gc=ctx.createGain(), lp=ctx.createBiquadFilter();\n      oc.type='triangle'; oc.frequency.value=AM_CHORD[bi];\n      lp.type='lowpass'; lp.frequency.value=600;\n      gc.gain.setValueAtTime(.12, now);\n      gc.gain.exponentialRampToValueAtTime(.001, now+dur*1.4);\n      oc.connect(lp); lp.connect(gc); gc.connect(_bgmGain);\n      oc.start(now); oc.stop(now+dur*1.4);\n    }\n\n    // Lead (cada 4 beats)\n    if(bi%4===0){\n      var ol=ctx.createOscillator(), gl=ctx.createGain();\n      ol.type='square'; ol.frequency.value=AM_LEAD[bi];\n      gl.gain.setValueAtTime(.07, now);\n      gl.gain.exponentialRampToValueAtTime(.001, now+dur*.9);\n      ol.connect(gl); gl.connect(_bgmGain);\n      ol.start(now); ol.stop(now+dur*.9);\n    }\n\n    // Hi-hat noise (beat 0 e 4)\n    if(bi===0||bi===4){\n      var buf=ctx.createBuffer(1,Math.floor(ctx.sampleRate*.04),ctx.sampleRate);\n      var bd=buf.getChannelData(0);\n      for(var i=0;i<bd.length;i++) bd[i]=(Math.random()*2-1)*.18;\n      var sn=ctx.createBufferSource(), hf=ctx.createBiquadFilter(), hg=ctx.createGain();\n      hf.type='highpass'; hf.frequency.value=4000;\n      hg.gain.setValueAtTime(.15,now); hg.gain.exponentialRampToValueAtTime(.001,now+.04);\n      sn.buffer=buf; sn.connect(hf); hf.connect(hg); hg.connect(_bgmGain);\n      sn.start(now);\n    }\n\n    BEAT_IDX++;\n    var drift = BEAT_MS - (BEAT_IDX * BEAT_MS % 20);\n    setTimeout(function(){ _scheduleBeat(session); }, Math.max(10, drift || BEAT_MS));\n  }\n\n  function startBGM(){\n    if(!_bgmOn) return;\n    init(); resume();\n    _session++;\n    var s = _session;\n    // Fade in suave\n    if(_bgmGain){\n      _bgmGain.gain.cancelScheduledValues(ctx.currentTime);\n      _bgmGain.gain.setValueAtTime(0, ctx.currentTime);\n      _bgmGain.gain.linearRampToValueAtTime(.22, ctx.currentTime+.5);\n    }\n    setTimeout(function(){ _scheduleBeat(s); }, 10);\n  }\n\n  function stopBGM(){\n    _session++; // invalida todos os loops ativos\n    if(_bgmGain && ctx){\n      _bgmGain.gain.cancelScheduledValues(ctx.currentTime);\n      _bgmGain.gain.setValueAtTime(_bgmGain.gain.value, ctx.currentTime);\n      _bgmGain.gain.linearRampToValueAtTime(0, ctx.currentTime+.3);\n    }\n  }\n\n  function toggleBGM(){\n    _bgmOn = !_bgmOn;\n    if(_bgmOn){ startBGM(); }\n    else{ stopBGM(); }\n    return _bgmOn;\n  }\n\n  function toggleSFX(){\n    _sfxOn = !_sfxOn;\n    return _sfxOn;\n  }\n\n  return {\n    init:init, resume:resume,\n    checkpoint:checkpoint, hit:hit, splash:splash, grass:grass, victory:victory,\n    startBGM:startBGM, stopBGM:stopBGM, toggleBGM:toggleBGM, toggleSFX:toggleSFX,\n    get bgmOn(){ return _bgmOn; },\n    get sfxOn(){ return _sfxOn; }\n  };\n})();\n")
w('client/src/core/Vector2D.js', '// Vector2D.js\nvar Vector2D = function(x,y){ this.x=x||0; this.y=y||0; };\nVector2D.prototype = {\n  add:        function(v){ return new Vector2D(this.x+v.x, this.y+v.y); },\n  sub:        function(v){ return new Vector2D(this.x-v.x, this.y-v.y); },\n  scale:      function(s){ return new Vector2D(this.x*s,   this.y*s);   },\n  magnitude:  function(){ return Math.sqrt(this.x*this.x + this.y*this.y); },\n  normalize:  function(){ var m=this.magnitude(); return m===0?new Vector2D(0,0):new Vector2D(this.x/m,this.y/m); },\n  distanceTo: function(v){ return this.sub(v).magnitude(); },\n  clone:      function(){ return new Vector2D(this.x, this.y); }\n};\n')
w('client/src/core/CapSprite.js', "// CapSprite.js - Tampinhas de garrafa (coroa metalica) + Pilotos anime\nvar CapSprite = (function(){\n\n  // Desenha uma tampinha realista (coroa de garrafa)\n  // color = cor principal, pilotKanji = kanji no centro\n  function drawCap(ctx, x, y, radius, color, accentColor, kanji, rotation, speed, glowAlpha){\n    ctx.save();\n    ctx.translate(x, y);\n    ctx.rotate(rotation);\n\n    // Glow de velocidade\n    if(speed > 80){\n      ctx.shadowColor  = color;\n      ctx.shadowBlur   = 10 + glowAlpha * 14;\n    }\n\n    // ── Corpo da tampinha (disco metalico) ──\n    // Sombra projetada\n    ctx.fillStyle='rgba(0,0,0,.35)';\n    ctx.beginPath();\n    ctx.ellipse(3,4,radius,radius*.4,0,0,Math.PI*2);\n    ctx.fill();\n\n    // Aba ondulada da coroa (fundo mais escuro)\n    var crownColor = shadeColor(color, -35);\n    ctx.fillStyle = crownColor;\n    ctx.beginPath();\n    var n = 21; // dentes da coroa\n    for(var i=0;i<n*2;i++){\n      var ang = (i/n)*Math.PI;\n      var r2  = i%2===0 ? radius : radius*.84;\n      if(i===0) ctx.moveTo(Math.cos(ang)*r2, Math.sin(ang)*r2);\n      else ctx.lineTo(Math.cos(ang)*r2, Math.sin(ang)*r2);\n    }\n    ctx.closePath();\n    ctx.fill();\n\n    // Disco principal (face da tampinha)\n    var grad = ctx.createRadialGradient(-radius*.25,-radius*.25, radius*.05, 0,0, radius*.95);\n    grad.addColorStop(0, lightenColor(color, 60));\n    grad.addColorStop(0.4, color);\n    grad.addColorStop(0.85, shadeColor(color,-20));\n    grad.addColorStop(1, shadeColor(color,-40));\n    ctx.fillStyle = grad;\n    ctx.beginPath();\n    ctx.arc(0,0,radius*.82,0,Math.PI*2);\n    ctx.fill();\n\n    // Anel metalico interno (borda impressa)\n    ctx.strokeStyle = shadeColor(color,-25);\n    ctx.lineWidth   = 1.8;\n    ctx.beginPath();\n    ctx.arc(0,0,radius*.72,0,Math.PI*2);\n    ctx.stroke();\n\n    // Area central (impressao)\n    ctx.fillStyle = 'rgba(0,0,0,.18)';\n    ctx.beginPath();\n    ctx.arc(0,0,radius*.60,0,Math.PI*2);\n    ctx.fill();\n\n    // Reflexo (brilho metalico)\n    var refGrad = ctx.createRadialGradient(-radius*.3,-radius*.32,1,-radius*.2,-radius*.2,radius*.45);\n    refGrad.addColorStop(0,'rgba(255,255,255,.55)');\n    refGrad.addColorStop(0.5,'rgba(255,255,255,.12)');\n    refGrad.addColorStop(1,'rgba(255,255,255,0)');\n    ctx.fillStyle = refGrad;\n    ctx.beginPath();\n    ctx.arc(0,0,radius*.82,0,Math.PI*2);\n    ctx.fill();\n\n    // Kanji do piloto (nao rotaciona com a tampinha)\n    ctx.rotate(-rotation);\n    ctx.fillStyle   = '#FFF';\n    ctx.font        = 'bold '+(radius*.55)+'px sans-serif';\n    ctx.textAlign   = 'center';\n    ctx.textBaseline= 'middle';\n    ctx.shadowBlur  = 0;\n    ctx.fillText(kanji || '?', 0, 1);\n\n    ctx.restore();\n  }\n\n  // Rastro / efeito dash de velocidade\n  function drawTrail(ctx, trail, color, speed){\n    if(!trail || trail.length<2) return;\n    // Dash lines (linhas de velocidade)\n    if(speed > 120){\n      var dashCount = Math.min(5, Math.floor(speed/120));\n      for(var d=0;d<dashCount;d++){\n        var idx1 = Math.max(0, trail.length-2-d*2);\n        var idx2 = Math.max(0, trail.length-4-d*2);\n        if(idx1===idx2) break;\n        var pt1=trail[idx1], pt2=trail[idx2];\n        var dx=pt2.x-pt1.x, dy=pt2.y-pt1.y;\n        var len=Math.sqrt(dx*dx+dy*dy);\n        if(len<2) break;\n        // perp offset para linhas de dash\n        var px=-dy/len*3, py=dx/len*3;\n        ctx.save();\n        ctx.globalAlpha=(0.5-d*.08)*Math.min(1,speed/300);\n        ctx.strokeStyle=color;\n        ctx.lineWidth=1.5-d*.2;\n        ctx.beginPath();\n        ctx.moveTo(pt1.x+px,pt1.y+py);\n        ctx.lineTo(pt2.x+px,pt2.y+py);\n        ctx.stroke();\n        ctx.beginPath();\n        ctx.moveTo(pt1.x-px,pt1.y-py);\n        ctx.lineTo(pt2.x-px,pt2.y-py);\n        ctx.stroke();\n        ctx.restore();\n      }\n    }\n    // Trilha de desvanecimento\n    for(var i=0;i<trail.length-1;i++){\n      var t=trail[i];\n      var a=(i/trail.length)*0.28;\n      ctx.save();\n      ctx.globalAlpha=a;\n      ctx.beginPath();\n      ctx.arc(t.x,t.y,11*(i/trail.length)+1,0,Math.PI*2);\n      ctx.fillStyle=color;\n      ctx.fill();\n      ctx.restore();\n    }\n  }\n\n  // Helpers de cor\n  function shadeColor(hex, pct){\n    var n=parseInt(hex.replace('#',''),16);\n    var r=Math.max(0,Math.min(255,((n>>16)&0xFF)+pct));\n    var g=Math.max(0,Math.min(255,((n>>8)&0xFF)+pct));\n    var b=Math.max(0,Math.min(255,(n&0xFF)+pct));\n    return '#'+((1<<24)+(r<<16)+(g<<8)+b).toString(16).slice(1);\n  }\n  function lightenColor(hex,pct){ return shadeColor(hex,pct); }\n\n  return { drawCap:drawCap, drawTrail:drawTrail };\n})();\n")
w('client/src/InputManager.js', "/**\n * InputManager.js — Captura de input do usuário\n * ───────────────────────────────────────────────\n * Gerencia arraste (mira + força), suporte a mouse e touch.\n * Emite eventos que a cena consome — não acessa Phaser diretamente.\n */\n\nimport { PHYSICS } from '../config/GameConfig.js';\nimport { Vec2 } from './Physics.js';\n\nexport class InputManager {\n  /**\n   * @param {Phaser.Scene} scene\n   * @param {Function} onLaunch  - callback({ dragStart, dragEnd, power, direction })\n   * @param {Function} onAiming  - callback({ dragStart, dragEnd, power }) durante arraste\n   * @param {Function} onCancel  - callback()\n   */\n  constructor(scene, onLaunch, onAiming, onCancel) {\n    this.scene    = scene;\n    this.active   = false; // só aceita input quando true\n    this.dragging = false;\n    this.start    = null;\n\n    scene.input.on('pointerdown', (p) => this._onDown(p));\n    scene.input.on('pointermove', (p) => this._onMove(p));\n    scene.input.on('pointerup',   (p) => this._onUp(p));\n\n    this._onLaunch  = onLaunch;\n    this._onAiming  = onAiming;\n    this._onCancel  = onCancel;\n  }\n\n  enable()  { this.active = true; }\n  disable() { this.active = false; this.dragging = false; }\n\n  _onDown(p) {\n    if (!this.active) return;\n    this.dragging = true;\n    this.start = new Vec2(p.x, p.y);\n  }\n\n  _onMove(p) {\n    if (!this.dragging || !this.active) return;\n    const end   = new Vec2(p.x, p.y);\n    const dx    = this.start.x - end.x;\n    const dy    = this.start.y - end.y;\n    const dist  = Math.min(Math.sqrt(dx*dx + dy*dy), PHYSICS.MAX_DRAG_PX);\n    const power = dist / PHYSICS.MAX_DRAG_PX;\n    this._onAiming?.({ dragStart: this.start, dragEnd: end, power });\n  }\n\n  _onUp(p) {\n    if (!this.dragging || !this.active) return;\n    this.dragging = false;\n    const end  = new Vec2(p.x, p.y);\n    const dx   = this.start.x - end.x;\n    const dy   = this.start.y - end.y;\n    const dist = Math.sqrt(dx*dx + dy*dy);\n    if (dist < 6) { this._onCancel?.(); return; }\n    this._onLaunch?.({ dragStart: this.start, dragEnd: end });\n  }\n}\n")
w('client/src/physics_config.js', "\n    // Phaser + Matter.js Config\n    const config = {\n        type: Phaser.AUTO,\n        physics: {\n            default: 'matter',\n            matter: {\n                gravity: { x: 0, y: 0 },\n                friction: 0.1,\n                restitution: 0.6, // Bounce\n                debug: true\n            }\n        },\n        scene: {\n            preload: preload,\n            create: create,\n            update: update\n        }\n    };\n    ")
